final:
module RefModule(
    input  [2:0] a,
    output [7:0] y
);

reg [7:0] unused_y_reg;

always @(*) begin
    case (a)
        3'b000: unused_y_reg = 8'b00000001;
        3'b001: unused_y_reg = 8'b00000010;
        3'b010: unused_y_reg = 8'b00000100;
        3'b011: unused_y_reg = 8'b00001000;
        3'b100: unused_y_reg = 8'b00010000;
        3'b101: unused_y_reg = 8'b00100000;
        3'b110: unused_y_reg = 8'b01000000;
        3'b111: unused_y_reg = 8'b10000000;
        default: unused_y_reg = 8'b00000000;
    endcase
end

assign y = unused_y_reg;

endmodule
